<#\n.SYNOPSIS\n  将 GLM Coding Helper Lite 打包为便携式 7z 压缩包\n  解压到任意位置即用，无需安装任何依赖\n\n.DESCRIPTION\n  自动检测 7-Zip 路径，将所有必要文件打成一个自包含的压缩包\n  建议配合 7zSFX 使用可制作双击自解压的 exe 安装包\n\n.EXAMPLE\n  .\pack.ps1                       # 打包为 7z 格式\n  .\pack.ps1 -Sfx                  # 打包为自解压 exe\n  .\pack.ps1 -Output "D:\backup"   # 指定输出目录\n#>\n\nparam(\n    [string]$OutputDir = (Split-Path -Parent $MyInvocation.MyCommand.Path),\n    [switch]$Sfx = $false\n)\n\n$Root = Split-Path -Parent $MyInvocation.MyCommand.Path\n$Timestamp = Get-Date -Format "yyyyMMdd"\n$ArchiveName = "GLM-Coding-Helper-Lite_$Timestamp"\n\nWrite-Host "=== GLM Coding Helper Lite 打包工具 ===" -ForegroundColor Cyan\nWrite-Host ""\n\n# ── 检测 7-Zip ─────────────────────────────────────────────────────────────\n$PathsToCheck = @(\n    "${env:ProgramFiles}\7-Zip\7z.exe",\n    "${env:ProgramFiles(x86)}\7-Zip\7z.exe",\n    "C:\Program Files\7-Zip\7z.exe",\n    "C:\Program Files (x86)\7-Zip\7z.exe"\n)\n$SevenZip = $null\nforeach ($p in $PathsToCheck) {\n    if (Test-Path $p) { $SevenZip = $p; break }\n}\nif (-not $SevenZip) {\n    Write-Host "[错误] 未找到 7-Zip!" -ForegroundColor Red\n    Write-Host "  请在 https://7-zip.org/download.html 下载安装" -ForegroundColor Yellow\n    Write-Host "  或手动将项目目录压缩为 zip 后使用" -ForegroundColor Yellow\n    exit 1\n}\nWrite-Host "  7-Zip: $SevenZip" -ForegroundColor Green\n\n# ── 检测输出目录 ────────────────────────────────────────────────────────────\nif (-not (Test-Path $OutputDir)) {\n    New-Item -Path $OutputDir -ItemType Directory -Force | Out-Null\n}\n$OutputPath = Join-Path $OutputDir "$ArchiveName.7z"\nif ($Sfx) {\n    $OutputPath = Join-Path $OutputDir "$ArchiveName.exe"\n}\n\n# ── 需要打包的目录和文件 ────────────────────────────────────────────────────\n$Include = @(\n    "backend"\n    "models"\n    ".paddlex_cache_cpu"\n    "python"\n    "venv\Lib\site-packages"\n    "venv\Scripts"\n    "venv\pyvenv.cfg"\n    "glm-lite.py"\n    "setup.ps1"\n    "start.bat"\n)\n\n# ── 排除不需要的文件（节省空间） ──────────────────────────────────────────────\n$ExcludeList = @(\n    "__pycache__"\n    "*.pyc"\n    ".git"\n    ".gitignore"\n    "dataset"          # 测试数据集，不需要打包\n    "logs"             # 运行日志\n)\n\n# ── 估算大小 ────────────────────────────────────────────────────────────────\nWrite-Host "" \nWrite-Host "[计算] 估算文件大小..." -NoNewline\n$totalBytes = 0\nforeach ($item in $Include) {\n    $fullPath = Join-Path $Root $item\n    if (Test-Path $fullPath) {\n        if ((Get-Item $fullPath).PSIsContainer) {\n            $totalBytes += (Get-ChildItem $fullPath -Recurse -File | Measure-Object Length -Sum).Sum\n        } else {\n            $totalBytes += (Get-Item $fullPath).Length\n        }\n    }\n}\n$totalMB = [math]::Round($totalBytes / 1MB, 1)\nWrite-Host " 约 ${totalMB}MB" -ForegroundColor Yellow\n\n# ── 打包 ────────────────────────────────────────────────────────────────────\nWrite-Host ""\nWrite-Host "[打包] 正在创建压缩包..." -ForegroundColor Cyan\nWrite-Host "  输出: $OutputPath"\nWrite-Host ""\n\n# 构建 7z 命令行参数\n$argList = @(\n    "a"                      # 添加到压缩包\n    "-t7z"                   # 7z 格式\n    "-mx=5"                  # 压缩级别 (0-9), 5=平衡\n    "-mmt=on"                # 多线程\n    "-m0=lzma2"              # LZMA2 算法\n    "-ms=on"                 # 固实压缩\n    "-myx=on"                # 按文件类型分析\n    "-mqs=on"                # 按文件名排序\n)\n\n# 添加排除规则\nforeach ($ex in $ExcludeList) {\n    $argList += "-xr!$ex"\n}\n\n$argList += "`"$OutputPath`""\n\n# 切换到项目根目录执行\nPush-Location $Root\ntry {\n    & $SevenZip $argList @Include\n    if ($LASTEXITCODE -eq 0) {\n        $sizeMB = [math]::Round((Get-Item $OutputPath).Length / 1MB, 1)\n        Write-Host ""\n        Write-Host "✓ 打包完成!" -ForegroundColor Green\n        Write-Host "  文件: $OutputPath" -ForegroundColor Cyan\n        Write-Host "  大小: ${sizeMB}MB" -ForegroundColor Cyan\n        Write-Host ""\n        Write-Host "使用方式:" -ForegroundColor Yellow\n        Write-Host "  1. 将压缩包复制到新电脑" -ForegroundColor Yellow\n        Write-Host "  2. 解压到任意位置（路径可以有中文，没问题）" -ForegroundColor Yellow\n        Write-Host "  3. 双击 start.bat 启动" -ForegroundColor Yellow\n    } else {\n        Write-Host "[错误] 打包失败 (exit code: $LASTEXITCODE)" -ForegroundColor Red\n    }\n} finally {\n    Pop-Location\n}\n